import React, { useState, useEffect } from "react";
import axios from "axios";
import { FaLock } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import "./resetpassword.css";

const ResetPassword = () => {
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const navigate = useNavigate();

  useEffect(() => {
    const userEmail = localStorage.getItem("resetEmail");
    if (!userEmail) {
      navigate("/forgot-password", { replace: true });
    }
  }, [navigate]);

  const handleResetPassword = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (!password || !confirmPassword) {
      setError("Both fields are required.");
      return;
    }

    if (password !== confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    try {
      setIsSubmitting(true);
      const userEmail = localStorage.getItem("resetEmail");
      const otpToken = localStorage.getItem("otpToken");

      if (!userEmail || !otpToken) {
        setError("Session expired. Please request a new OTP.");
        return;
      }

      console.log("Sending Reset Password Request:", { email: userEmail, password, otpToken });

      const response = await axios.post(
        "http://localhost:5000/api/auth/reset-password",
        { email: userEmail, password, otpToken },
        { headers: { "Content-Type": "application/json" } }
      );

      if (response.data.success) {
        setMessage("Password reset successfully!");
        localStorage.removeItem("resetEmail");
        localStorage.removeItem("otpToken");

        setTimeout(() => navigate("/login"), 1000);
      } else {
        setError(response.data.message || "Error resetting password.");
      }
    } catch (err) {
      console.error("Reset Password Error:", err);
      if (err.response) {
        setError(err.response.data.message || "Server error. Try again.");
      } else {
        setError("Network error. Please try again.");
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="reset-password-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />
      <div className="reset-password-card">
        <h2>Reset Password</h2>
        <p>Enter your new password below.</p>

        <form onSubmit={handleResetPassword}>
          <div className="input-group">
            <FaLock className="icon" />
            <input
              type="password"
              placeholder="New Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              disabled={isSubmitting}
            />
          </div>

          <div className="input-group">
            <FaLock className="icon" />
            <input
              type="password"
              placeholder="Confirm Password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
              disabled={isSubmitting}
            />
          </div>

          <button type="submit" className="reset-password-button" disabled={isSubmitting}>
            {isSubmitting ? "Resetting..." : "Reset Password"}
          </button>

          <div className="message-container">
            {message && <p className="success-message">{message}</p>}
            {error && <p className="error-message">{error}</p>}
          </div>
        </form>
      </div>

      <button onClick={() => navigate("/forgot-password")} className="back-button">
        Back
      </button>
    </div>
  );
};

export default ResetPassword;
